    public void addContact(Contact contact) {
        contacts.add(contact);
        sort();
    }

    // Insertion sort is a good choice since it's efficient 
    // for lists that are almost sorted. After adding a new contact, 
    // the list is only partially unsorted.
    private void sort() {
        for (int i = 1; i < contacts.size(); i++) {
            Contact key = contacts.get(i);
            int j = i - 1;

            // Compare and shift
            while (j >= 0 && contacts.get(j).getName().compareTo(key.getName()) > 0) {
                contacts.set(j + 1, contacts.get(j));
                j = j - 1;
